# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using UnityEngine.UI;
using System;

public class PlayerStats : MonoBehaviour
{
    public int playerHealth = 100;
    public int maxHealth = 100;
    public int currency = 0;
    public int damage = 10;

    public void TakeDamage(int amount)
    {
        int finalDamage = Mathf.Max(0, amount);
        playerHealth = Mathf.Max(0, playerHealth - finalDamage);
    }

    public void Heal(int amount)
    {
        int finalHeal = Mathf.Max(0, amount);
        playerHealth = Mathf.Min(maxHealth, playerHealth + finalHeal);
    }

    public void AddCurrency(int amount)
    {
        currency = Mathf.Max(0, currency + Mathf.Max(0, amount));
    }

    public bool SpendCurrency(int amount)
    {
        amount = Mathf.Max(0, amount);
        if (currency < amount) return false;
        currency -= amount;
        return true;
    }

    public void IncreaseDamage(int amount)
    {
        damage = Mathf.Max(0, damage + Mathf.Max(0, amount));
    }
}

[Serializable]
public class ShopItem
{
    public string itemName;
    public int basePrice = 100;
    public int priceMultiplier = 2;
    public int priceLevel = 0;
    public int damageBonus = 0;
    public int healthBonus = 0;

    public int GetPrice()
    {
        int price = basePrice;
        for (int i = 0; i < priceLevel; i++)
        {
            price *= Mathf.Max(1, priceMultiplier);
        }
        return Mathf.Max(0, price);
    }

    public void Purchase(PlayerStats player)
    {
        int price = GetPrice();
        if (player == null) return;
        if (!player.SpendCurrency(price)) return;

        priceLevel++;

        if (damageBonus != 0)
            player.IncreaseDamage(damageBonus);

        if (healthBonus != 0)
        {
            player.maxHealth = Mathf.Max(1, player.maxHealth + healthBonus);
            player.playerHealth = Mathf.Min(player.playerHealth + healthBonus, player.maxHealth);
        }
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats player;
    public ShopItem[] items;

    public void BuyItem(int index)
    {
        if (player == null) return;
        if (items == null) return;
        if (index < 0 || index >= items.Length) return;

        items[index].Purchase(player);
    }

    public int GetItemPrice(int index)
    {
        if (items == null) return 0;
        if (index < 0 || index >= items.Length) return 0;
        return items[index].GetPrice();
    }
}

public class SimpleCombat : MonoBehaviour
{
    public PlayerStats player;

    public void DealDamageToPlayer(int rawDamage, float multiplier)
    {
        if (player == null) return;
        int calculatedDamage = Mathf.Max(0, Mathf.RoundToInt(rawDamage * multiplier));
        player.TakeDamage(calculatedDamage);
    }
}

public class CurrencyReward : MonoBehaviour
{
    public PlayerStats player;
    public int rewardAmount = 10;

    public void GrantReward()
    {
        if (player == null) return;
        player.AddCurrency(rewardAmount);
    }
}